// SPDX-License-Identifier: MIT
pragma solidity 0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

/**
 * @notice USDm-funded game settlement scaffold. Integrate a production-reviewed
 * Chainlink VRF consumer before handling deposits on any live network.
 */
contract Xopredict is Ownable, ReentrancyGuard, Pausable {
    IERC20 public immutable usdm;
    uint256 public maxBetPerTx = 20e18;
    uint256 public maxBetPerDay = 100e18;
    uint256 public arenaCount;

    struct Arena { uint256 betAmount; uint8 maxPlayers; uint8 playerCount; bool settled; address winner; }
    mapping(uint256 => Arena) public arenas;
    mapping(address => uint256) public dailyBetTotal;

    event ArenaCreated(uint256 indexed arenaId, uint256 betAmount, uint8 maxPlayers);
    event PlayerJoined(uint256 indexed arenaId, address indexed player);
    event CardPicked(uint256 indexed arenaId, address indexed player, uint8 cardIndex);
    event RoundRevealed(uint256 indexed arenaId, bytes32 commitment);
    event WinnerPaid(uint256 indexed arenaId, address indexed winner, uint256 amount);
    event SoloPlayed(address indexed player, uint256 betAmount, uint8 cardIndex);

    constructor(address usdmAddress) Ownable(msg.sender) { usdm = IERC20(usdmAddress); }

    function createArena(uint256 betAmount, uint8 maxPlayers) external whenNotPaused nonReentrant returns (uint256 arenaId) {
        require(maxPlayers >= 2 && maxPlayers <= 6, "invalid player count");
        _takeBet(msg.sender, betAmount);
        arenaId = ++arenaCount;
        arenas[arenaId] = Arena(betAmount, maxPlayers, 1, false, address(0));
        emit ArenaCreated(arenaId, betAmount, maxPlayers);
    }

    function joinArena(uint256 arenaId) external whenNotPaused nonReentrant {
        Arena storage arena = arenas[arenaId];
        require(arena.playerCount > 0 && arena.playerCount < arena.maxPlayers, "arena unavailable");
        _takeBet(msg.sender, arena.betAmount);
        arena.playerCount++;
        emit PlayerJoined(arenaId, msg.sender);
    }

    function pickCard(uint256 arenaId, uint8 cardIndex) external whenNotPaused {
        require(cardIndex > 0, "invalid card");
        emit CardPicked(arenaId, msg.sender, cardIndex);
    }

    function startSoloGame(uint256 betAmount) external whenNotPaused nonReentrant { _takeBet(msg.sender, betAmount); }
    function pickSoloCard(uint256 gameId, uint8 cardIndex) external whenNotPaused { require(cardIndex < 2, "invalid card"); emit SoloPlayed(msg.sender, gameId, cardIndex); }
    function pause() external onlyOwner { _pause(); }
    function unpause() external onlyOwner { _unpause(); }
    function setMaxBet(uint256 perTx, uint256 perDay) external onlyOwner { maxBetPerTx = perTx; maxBetPerDay = perDay; }

    function _takeBet(address player, uint256 amount) internal {
        require(amount > 0 && amount <= maxBetPerTx, "bet limit");
        require(dailyBetTotal[player] + amount <= maxBetPerDay, "daily limit");
        dailyBetTotal[player] += amount;
        require(usdm.transferFrom(player, address(this), amount), "transfer failed");
    }
}

